package com.agmsolutions.fabrick_test.controller;import com.agmsolutions.fabrick_test.Model.dto.BalanceDto;import com.agmsolutions.fabrick_test.Model.dto.MoneyTransferBodyDto;import com.agmsolutions.fabrick_test.Model.dto.MoneyTransferResponseDto;import com.agmsolutions.fabrick_test.Model.dto.TransactionDto;import com.agmsolutions.fabrick_test.service.AccountService;import jakarta.validation.Valid;import lombok.AllArgsConstructor;import org.springframework.format.annotation.DateTimeFormat;import org.springframework.validation.annotation.Validated;import org.springframework.web.bind.annotation.*;import java.time.LocalDate;import java.util.List;@RestController@RequestMapping("api/account")@AllArgsConstructor@Validatedpublic class AccountController {    private final AccountService accountService;    @GetMapping("/balance")    public BalanceDto getBalance(@RequestParam(value = "accountId") Long accountId) {        return accountService.getBalance(accountId);    }    @GetMapping("/transactions")    public List<TransactionDto> getTransactions(@RequestParam(value = "accountId") Long accountId,                                                @RequestParam(value = "dateStart") @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate dateStart,                                                @RequestParam(value = "dateEnd") @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate dateEnd) {        return accountService.getTransactions(accountId, dateStart, dateEnd);    }        @PostMapping("/transfer")    public MoneyTransferResponseDto createMoneyTransfer(@RequestParam(value = "accountId") Long accountId,                                                        @RequestBody @Valid MoneyTransferBodyDto body){        return accountService.createMoneyTransfer(accountId, body);    }}